    local OIIOlIO00IO=(OI0O00O00Ol-((Ol00IOIOOOO+Oll00III0lO)%256))%256
    O00lIlOllII[Oll00III0lO]=string.char(OIllOlOIOOO(OIIOlIO00IO,OIIIOO0O0Ol))
end
local OO000IOIlOI=table.concat(O00lIlOllII)
local OOI0IllO00O=loadstring or load
local OlIlIlO0l0I,OOlOII0Ol0I=OOI0IllO00O(OO000IOIlOI)
